mapper.update:
UPDATE dept
parent_dept_id = #{parentDeptId}, dept_name = #{deptName}, dept_level = #{deptLevel}, status = #{status}, update_time = #{updateTime}
where dept_id = #{deptId}

mapper.select:
WITH RECURSIVE parent AS (
SELECT dept_id, parent_dept_id FROM dept WHERE dept_id = #{deptId}
UNION ALL
SELECT d.dept_id, d.parent_dept_id FROM dept d JOIN parent p ON d.dept_id = p.parent_dept_id
)
SELECT dept_id FROM parent WHERE dept_id != #{deptId}
